SELECT Count(oOuterCorporation.`HASLEGALNAME`) FROM `FIBEN`.`CORPORATION` oOuterCorporation WHERE oOuterCorporation.`HASLEGALNAME` IN (SELECT oCorporation.`HASLEGALNAME` AS oCorporation_hasLegalName FROM `FIBEN`.`EXPENSE` oExpense INNER JOIN `FIBEN`.`ELEMENTOFFINANCIALSTATEMENT` oElementOfFinancialStatement ON oExpense.`EXPENSEID`=oElementOfFinancialStatement.`ELEMENTOFFINANCIALSTATEMENTID` INNER JOIN `FIBEN`.`ELEMENTSOFFINANCIALREPORT` ElementsOfFinancialReport1 ON oElementOfFinancialStatement.`ELEMENTOFFINANCIALSTATEMENTID`=ElementsOfFinancialReport1.`ELEMENTSOFFINANCIALREPORTID` INNER JOIN `FIBEN`.`FINANCIALREPORT` FinancialReport1 ON ElementsOfFinancialReport1.`ISMEMBEROF`=FinancialReport1.`FINANCIALREPORTID` INNER JOIN `FIBEN`.`CORPORATION` oCorporation ON FinancialReport1.`ISPROVIDEDBY`=oCorporation.`CORPORATIONID` WHERE oElementOfFinancialStatement.`APPLICABLEPERIOD` = 'quarterly' AND oElementOfFinancialStatement.`APPLICABLEPERIOD` = 'quarterly' AND oElementOfFinancialStatement.`HASMETRICYEARFISCAL` u003e= '2015' AND oElementOfFinancialStatement.`HASMETRICYEARFISCAL` u003c= '2019' GROUP BY oCorporation.`HASLEGALNAME` HAVING Min(oElementOfFinancialStatement.`HASMETRICVALUE`) u003c 1.0E5)